import { readFileSync } from "node:fs";
import { join } from "node:path";
import { renderFlow, TARGETS } from "bitfab-flow";
import { describe, expect, it } from "vitest";
import { updateFlow } from "./update.js";
const REPO_ROOT = join(__dirname, "..", "..", "..");
// The root file (slug "") is the monolith for Cursor/Codex and the split
// orchestrator for Claude; both land at the path below.
const UPDATE_PATHS = {
    claude: "bitfab-claude-plugin/skills/update/SKILL.md",
    cursor: "bitfab-cursor-plugin/skills/bitfab-update/SKILL.md",
    codex: "bitfab-codex-plugin/skills/update/SKILL.md",
};
describe("renderFlow(updateFlow)", () => {
    for (const targetName of Object.keys(UPDATE_PATHS)) {
        it(`matches the committed ${targetName} update skill byte-for-byte`, () => {
            const target = TARGETS[targetName];
            const root = renderFlow(updateFlow, target).find((f) => f.slug === "");
            const committedPath = join(REPO_ROOT, UPDATE_PATHS[targetName]);
            const committed = readFileSync(committedPath, "utf-8");
            expect(root?.content).toBe(committed);
        });
    }
});
